453→	private cleanText({ text }: { text: string | null | undefined }): string {
454→		if (!text) return '';
455→		return text
456→			.replace(/\r\n|\r|\n/g, ' ')
457→			.replace(/[*#]+\s?/g, '')
458→			.replace(/<[^>]*>/g, '')
459→			.replace(/\s{2,}/g, ' ')
460→			.trim();
461→	}
